describe('GET /api/tasks', () => {
  const mockTasks = [
    { id: 'task-1', title: 'Task 1', difficulty: 'easy', description: 'Desc 1', version: '1.0', status: 'published' as const },
    { id: 'task-2', title: 'Task 2', difficulty: 'medium', description: 'Desc 2', version: '1.0', status: 'published' as const },
    { id: 'task-3', title: 'Task 3', difficulty: 'hard', description: 'Desc 3', version: '1.0', status: 'published' as const },
  ];

  it('should return all tasks when no filters provided', async () => {
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    vi.mocked(getTasks).mockResolvedValue(mockTasks as any);

    const request = new NextRequest('http://localhost/api/tasks');
    const response = await tasksHandler(request);
    const data = await response.json();

    expect(response.status).toBe(200);
    expect(data.count).toBe(3);
    expect(data.tasks).toHaveLength(3);
  });

  it('should filter tasks by difficulty', async () => {
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    vi.mocked(getTasks).mockResolvedValue(mockTasks as any);

    const request = new NextRequest('http://localhost/api/tasks?difficulty=medium');
    const response = await tasksHandler(request);
    const data = await response.json();

    expect(response.status).toBe(200);
    expect(data.count).toBe(1);
    expect(data.tasks[0].id).toBe('task-2');
  });

  describe('status filter', () => {
    const mixedStatusTasks = [
      { id: 'task-1', title: 'Task 1', difficulty: 'easy', description: 'Desc 1', version: '1.0', status: 'published' as const },
      { id: 'task-2', title: 'Task 2', difficulty: 'medium', description: 'Desc 2', version: '1.0', status: 'published' as const },
      { id: 'task-3', title: 'Task 3', difficulty: 'hard', description: 'Desc 3', version: '1.0', status: 'published' as const },
      { id: 'task-4', title: 'Task 4', difficulty: 'easy', description: 'Desc 4', version: '1.0', status: 'draft' as const },
      { id: 'task-5', title: 'Task 5', difficulty: 'medium', description: 'Desc 5', version: '1.0', status: 'review' as const },
      { id: 'task-6', title: 'Task 6', difficulty: 'hard', description: 'Desc 6', version: '1.0', status: 'draft' as const },
    ];

    it('should filter tasks by status=draft', async () => {
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      vi.mocked(getTasks).mockResolvedValue(mixedStatusTasks as any);

      const request = new NextRequest('http://localhost/api/tasks?status=draft');
      const response = await tasksHandler(request);
      const data = await response.json();

      expect(response.status).toBe(200);
      expect(data.count).toBe(2);
      expect(data.tasks.map((t: { id: string }) => t.id).sort()).toEqual(['task-4', 'task-6']);
    });

    it('should filter tasks by status=review', async () => {
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      vi.mocked(getTasks).mockResolvedValue(mixedStatusTasks as any);

      const request = new NextRequest('http://localhost/api/tasks?status=review');
      const response = await tasksHandler(request);
      const data = await response.json();

      expect(response.status).toBe(200);
      expect(data.count).toBe(1);
      expect(data.tasks[0].id).toBe('task-5');
    });

    it('should filter tasks by status=published', async () => {
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      vi.mocked(getTasks).mockResolvedValue(mixedStatusTasks as any);

      const request = new NextRequest('http://localhost/api/tasks?status=published');
      const response = await tasksHandler(request);
      const data = await response.json();

      expect(response.status).toBe(200);
      expect(data.count).toBe(3);
      expect(data.tasks.every((t: { status: string }) => t.status === 'published')).toBe(true);
    });

    it('should ignore invalid status values and return all tasks', async () => {
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      vi.mocked(getTasks).mockResolvedValue(mixedStatusTasks as any);

      const request = new NextRequest('http://localhost/api/tasks?status=archived');
      const response = await tasksHandler(request);
      const data = await response.json();

      expect(response.status).toBe(200);
      expect(data.count).toBe(6);
      expect(data.tasks).toHaveLength(6);
    });

    it('should combine difficulty and status filters', async () => {
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      vi.mocked(getTasks).mockResolvedValue(mixedStatusTasks as any);

      const request = new NextRequest('http://localhost/api/tasks?difficulty=easy&status=draft');
      const response = await tasksHandler(request);
      const data = await response.json();

      expect(response.status).toBe(200);
      expect(data.count).toBe(1);
      expect(data.tasks[0].id).toBe('task-4');
    });

    it('should return empty list when difficulty and status filters do not match any task', async () => {
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      vi.mocked(getTasks).mockResolvedValue(mixedStatusTasks as any);

      const request = new NextRequest('http://localhost/api/tasks?difficulty=hard&status=review');
      const response = await tasksHandler(request);
      const data = await response.json();

      expect(response.status).toBe(200);
      expect(data.count).toBe(0);
      expect(data.tasks).toHaveLength(0);
    });
  });
});

